    smells = []
    for i, line in enumerate(lines):
        if len(line.rstrip()) > 100:
            smells.append(Smell("long_line", 1, i + 1,
                f"Line is {len(line.rstrip())} chars (>100)",
                "Break into multiple lines"))
    return smells


def _detect_excessive_globals(lines):
